-- Dual-backend: persist DATE columns (DuckDB stores VARCHAR wire), then BETWEEN vs >= / <=.
-- First 10 rows: StartDateA lies in [StartDateB, EndDateB] (is_between = is_range = 1).
-- Remaining rows: ranges chosen so StartDateA is outside [StartDateB, EndDateB] (both flags 0).

CREATE TABLE date_cmp_seed AS
SELECT * FROM UNNEST([
  STRUCT(DATE '2010-01-25' AS StartDateA, DATE '2010-01-25' AS StartDateB, DATE '2010-06-11' AS EndDateB),
  STRUCT(DATE '2013-08-27', DATE '2013-08-27', DATE '2014-01-17'),
  STRUCT(DATE '2011-08-23', DATE '2011-08-23', DATE '2012-01-20'),
  STRUCT(DATE '2011-08-23', DATE '2011-08-23', DATE '2012-01-02'),
  STRUCT(DATE '2009-01-12', DATE '2009-01-12', DATE '2009-03-27'),
  STRUCT(DATE '2011-03-04', DATE '2011-03-04', DATE '2011-06-10'),
  STRUCT(DATE '2008-08-19', DATE '2008-08-19', DATE '2008-12-19'),
  STRUCT(DATE '2009-01-12', DATE '2009-01-12', DATE '2009-06-03'),
  STRUCT(DATE '2008-08-19', DATE '2008-08-19', DATE '2008-09-16'),
  STRUCT(DATE '2008-08-20', DATE '2008-08-20', DATE '2008-12-19'),
  STRUCT(DATE '2010-01-25', DATE '2006-08-29', DATE '2007-01-18'),
  STRUCT(DATE '2010-01-25', DATE '2007-01-22', DATE '2007-06-08'),
  STRUCT(DATE '2010-01-25', DATE '2007-08-20', DATE '2007-12-21'),
  STRUCT(DATE '2010-01-25', DATE '2008-01-07', DATE '2008-05-29'),
  STRUCT(DATE '2010-01-25', DATE '2008-08-19', DATE '2008-12-19'),
  STRUCT(DATE '2010-01-25', DATE '2009-01-12', DATE '2009-06-03'),
  STRUCT(DATE '2010-01-25', DATE '2009-08-25', DATE '2010-01-22'),
  STRUCT(DATE '2010-01-25', DATE '2010-08-24', DATE '2011-01-21'),
  STRUCT(DATE '2010-01-25', DATE '2011-01-24', DATE '2011-06-10'),
  STRUCT(DATE '2013-08-27', DATE '2012-08-21', DATE '2013-01-18')
]);

SELECT
  CAST(StartDateA AS STRING) AS start_a,
  CAST(StartDateB AS STRING) AS start_b,
  CAST(EndDateB AS STRING) AS end_b,
  CAST(StartDateA BETWEEN StartDateB AND EndDateB AS INT64) AS is_between,
  CAST((StartDateA >= StartDateB AND StartDateA <= EndDateB) AS INT64) AS is_range
FROM date_cmp_seed
ORDER BY start_a, start_b, end_b;
